 1	import React, { FC } from 'react';
 2	
 3	import { Table, TableGridBreakpoint, Tbody, Th, Thead, Tr } from '@patternfly/react-table';
 4	import { NodeNetworkConfigurationInterface, V1beta1NodeNetworkState } from '@types';
 5	
 6	import useInterfaceColumns from '../hooks/useInterfaceColumns';
 7	
 8	import InterfacesTypeSection from './InterfacesTypeSection';
 9	
10	import './interfaces-table.scss';
11	
12	interface InterfacesTableProps {
13	  interfacesByType: { [interfaceType in string]: NodeNetworkConfigurationInterface[] };
14	  nodeNetworkState: V1beta1NodeNetworkState;
15	  expandAll: boolean;
16	}
17	
18	const InterfacesTable: FC<InterfacesTableProps> = ({
19	  interfacesByType,
20	  nodeNetworkState,
21	  expandAll,
22	}) => {
23	  const columns = useInterfaceColumns();
24	
25	  return (
26	    <Table
27	      gridBreakPoint={TableGridBreakpoint.none}
28	      role="presentation"
29	      className="interfaces-table"
30	    >
31	      <Thead>
32	        <Tr>
33	          {columns.map((column) => (
34	            <Th key={column.id} {...column?.props}>
35	              {column.title}
36	            </Th>
37	          ))}
38	        </Tr>
39	      </Thead>
40	      <Tbody>
41	        {Object.keys(interfacesByType)
42	          .sort()
43	          .map((interfaceType) => (
44	            <InterfacesTypeSection
45	              key={interfaceType}
46	              interfaceType={interfaceType}
47	              interfaces={interfacesByType[interfaceType]}
48	              nodeNetworkState={nodeNetworkState}
49	              expandAll={expandAll}
50	            />
51	          ))}
52	      </Tbody>
53	    </Table>
54	  );
55	};
56	
57	export default InterfacesTable;

